@if (toolbarVisible) {
  <mat-toolbar class="rfq-toolbar">
    <div class="toolbar-left">
      @if (role !='vendor') {
        <button
          mat-flat-button
          color="accent"
          class="create-btn"
          (click)="onNewProduct()">
          <mat-icon>add</mat-icon>
