+    const value = params.data?.[field] ?? '';
+    const text = document.createElement('span');
+    text.className = 'tech-pack-cell__text';
+    text.textContent = value || 'No link';
+    text.title = value || 'Double-click or use Edit to add a link';
+
+    const editButton = document.createElement('button');
+    editButton.type = 'button';
+    editButton.className = 'tech-pack-cell__button';
+    editButton.title = 'Edit Tech Pack Link';
+    editButton.setAttribute('aria-label', 'Edit Tech Pack Link');
+    editButton.textContent = 'Edit';
+    editButton.addEventListener('click', (event) => {
+      event.preventDefault();
+      event.stopPropagation();
+      params.api.startEditingCell({
+        rowIndex: params.node.rowIndex,
+        colKey: params.column.getColId(),
+        rowPinned: params.node.rowPinned,
+      });
+    });
+
+    const openButton = document.createElement('button');
+    openButton.type = 'button';
+    openButton.className = 'tech-pack-cell__button';
+    openButton.title = value ? 'Open Tech Pack Link' : 'No Tech Pack Link';
+    openButton.setAttribute('aria-label', 'Open Tech Pack Link');
+    openButton.textContent = 'Open';
+    openButton.disabled = !value;
+    openButton.addEventListener('click', (event) => {
+      event.preventDefault();
+      event.stopPropagation();
+      if (value) {
+        window.open(value, '_blank', 'noopener');
+      }
+    });
+
