  private filterColumnsByRole(colHeaders: any[], role: string): any[] {
    // If no role is provided, return all columns
    if (!role) {
      return colHeaders;
    }
    
    return colHeaders.filter((col: any) => {
      // If column has no roles property or empty roles array, it's visible to all
